/* [General Settings] */
// Resolution of curves
$fn = 100; // [20:200]

/* [Dimensions] */
// Distance from center to the outer edge
outer_radius = 204;  
// Distance from center to the inner curve
inner_radius = 120;   
// Thickness of the top mesh
platform_thickness = 3;
// The sweep of the arc in degrees
arc_angle = 30; // [5:180]

/* [Grid & Spokes] */
// Distance between the rings
ring_spacing = 6; 
// Number of radial support beams
spoke_count = 4; // [2:20]
// Width of the ribs and spokes
rib_width = 2.0;

/* [Clip & Hook] */
// Total height of the attachment clip
clip_height = 20;    
// Thickness of the clip walls
wall_thickness = 3;  
// The gap width for the rim to slot into
rim_gap = 4.5;

radial_platform();

// --- Modules ---

module radial_platform() {
    union() {
        intersection() {
            // Move the wedge down so it covers from -clip_height up to platform_thickness
            translate([0, 0, -clip_height])
                pie_wedge(outer_radius + rib_width/2, arc_angle, clip_height + platform_thickness); 
            
            grid_elements();
        }
        
        translate([0, 0, platform_thickness - clip_height])
            curved_rim_clip();
    }
}

module grid_elements() {
    union() {
        // --- FIXED RING CALCULATION ---
        // Calculate the angular "thickness" of one rib at the inner radius
        spoke_angle_offset = (rib_width/2 / inner_radius) * (180 / 3.14159);
        
        // The usable span where the spokes actually live
        usable_angle = arc_angle - (spoke_angle_offset * 2);

        // Clip the rings so they don't stick out past the spokes
        intersection() {
            pie_wedge(outer_radius + rib_width, usable_angle, platform_thickness);
            
            union() {
                for (r = [inner_radius : ring_spacing : outer_radius]) {
                    difference() {
                        cylinder(r = r + rib_width/2, h = platform_thickness);
                        translate([0, 0, -1])
                            cylinder(r = r - rib_width/2, h = platform_thickness + 2);
                    }
                }
            }
        }

        // --- SPOKES AND YOUR SPECIFIC GUSSETS ---
        spoke_length = outer_radius - inner_radius;
        
        for (i = [0 : spoke_count - 1]) {
            angle = -usable_angle/2 + (i * usable_angle / (spoke_count - 1));
            
            rotate([0, 0, angle]) {
                // 1. Horizontal Spoke
                translate([inner_radius - wall_thickness, -rib_width/2, 0])
                    cube([spoke_length + wall_thickness + rib_width, rib_width, platform_thickness]);
                
                // 2. Diagonal Gusset (PRESERVED EXACTLY)
                translate([inner_radius + rim_gap, rib_width/2, platform_thickness - clip_height])
                    rotate([90, 0, 0]) 
                        linear_extrude(height = rib_width)
                            polygon(points = [
                                [0, 0], 
                                [spoke_length/3, clip_height - platform_thickness], 
                                [0, clip_height - platform_thickness]
                            ]);
            }
        }
    }
}

module curved_rim_clip() {
    rotate([0, 0, -arc_angle/2])
    rotate_extrude(angle = arc_angle) {
        translate([inner_radius - wall_thickness, 0, 0]) {
            difference() {
                square([rim_gap + (wall_thickness * 2), clip_height]);
                translate([wall_thickness, -1])
                    square([rim_gap, clip_height - wall_thickness + 1]);
            }
        }
    }
}

module pie_wedge(r, angle, h) {
    linear_extrude(height = h) {
        polygon(points = [
            [0, 0], 
            for (i = [0 : $fn]) 
                let (a = -angle/2 + i * angle / $fn) 
                [r * cos(a), r * sin(a)], 
            [0, 0]
        ]);
    }
}

// CONFIG
$fn=100;

Name = "ERASMO";
Font = "Bungee"; // [Archivo Black, Bangers, Bungee, Changa One, Bebas Neue, Poppins Black, Chewy, Bagel fat one, Agbalumo, Angkor, Acme, Amaranth, Bayon, Badeen display, Arbutus, Anton sc, Adlam display, Alfa slab one, Anton, Bakbak one, Archivio black, Aoboshi one, ]
F_s = 16;

Text_height = 2;
Border_size = 3;
Base_h = 15;             
Pencil_diameter = 7.3;
Clearance = 0.6;
_r = (Pencil_diameter+Clearance)/2;
// COLOR OPTIONS
colors = ["red", "blue", "green", "yellow", "orange", "purple","pink", "gray", "black", "white"];
Base_color = "Gray";  // [Red, Green, Blue, Yellow, Orange, Purple, Pink, White, Black, Gray, Turquoise]
Text_color = "Turquoise";  // [Red, Green, Blue, Yellow, Orange, Purple, Pink, White, Black, Gray, Turquoise]

//Variables for alternating letters
/* [Settings for Alternating Letters] */
//Activate Alternated letters
activate_alternate = true; // [true,false]
spacing = 0.75; // [0.1:0.05:2]
// Height for odd letters
height_odd = 17;
// Height for even letters
height_even = 15;
/* [Individual adjustments for alternating letters] */
//Letter positions 1
pos_1 = 0; // [-8:0.1:8]
//Letter positions 2
pos_2 = 0; // [-8:0.1:8]
//Letter positions 3
pos_3 = 0; // [-8:0.1:8]
//Letter positions 4
pos_4 = 0; // [-8:0.1:8]
//Letter positions 5
pos_5 = 0; // [-8:0.1:8]
//Letter positions 6
pos_6 = 0; // [-8:0.1:8]
//Letter positions 7
pos_7 = 0; // [-8:0.1:8]
//Letter positions 8
pos_8 = 0; // [-8:0.1:8]
//Letter positions 9
pos_9 = 0; // [-8:0.1:8]
//Letter positions 10
pos_10 = 0; // [-8:0.1:8]
//Letter positions 11
pos_11 = 0; // [-8:0.1:8]
//Letter positions 12
pos_12 = 0; // [-8:0.1:8]

// MODEL
//funBasePlate();
if (activate_alternate) BasePlateALT(); else funBase();

module funBase() {
    funBasePlate();
    funText();
    }    
module funBasePlate() {
    difference() {
    color(Base_color)                         // Apply back color to base
        linear_extrude(Base_h, convexity=10){
            offset(r=Border_size) fun2DText();
        };
        translate([0, 0, Base_h/2]) rotate([0, 90, 0]) cylinder(200,r=_r, center = true, $fn=64);
    }    
}

module funText(){
    color(Text_color)                         // Apply text color
        translate([0,0,Base_h])           // Position text on top of backplate
            linear_extrude(Text_height){ 
                fun2DText();
            }
}
module fun2DText() {
    text(Name, size=F_s, font=Font, halign="center", valign="center");
}

function get_height(pos) = (pos % 2 == 0) ? height_odd : height_even;
function get_adjust(pos) = pos == 0 ? pos_1 : pos == 1 ? pos_2 : pos == 2 ? pos_3 : pos == 3 ? pos_4 : pos == 4 ? pos_5 : pos == 5 ? pos_6 : pos == 6 ? pos_7 : pos == 7 ? pos_8 : pos == 8 ? pos_9 : pos == 9 ? pos_10 : pos == 10 ? pos_11 : pos == 11 ? pos_12 : 0;
function get_TOTadjust(pos) = pos < 0 ? 0 : get_TOTadjust(pos - 1) + get_adjust(pos);
module BasePlateALT() {
    difference() {
    for (i = [0:len(Name)-1]) {
    letter = Name[i];
    letter_height = get_height(i);
    pos_x = i * (F_s * spacing) + get_TOTadjust(i);
  
    color(Base_color)
    translate([pos_x, 0, 0])
    linear_extrude(height=letter_height, convexity=10)
    text(letter, 
    font=Font, 
    size=F_s,
    valign="center"
    );
}
    translate([0, 0, Base_h/2]) rotate([0, 90, 0]) cylinder(200,r=_r, center = true, $fn=64);
    }
}

// ======================================================
//  PARAMETRIC 4-WAY CONNECTOR
//  Part of the Modular Connectors system by iw3d
//
//  This connector joins three horizontal rods/tubes
//  and one tilted vertical rod.
//
//  Fully customizable parameters:
//  • rod diameters
//  • arm lengths
//  • tilt angle
//  • wall thickness
//  • clearance
//
//  Designed for MakerWorld Customizer.
// ======================================================

// ======================================================
// === USER PARAMETERS (safe to edit) ===================
// ======================================================

// --> rod / pipe diameter along X axis
rod_diameter_x_mm   = 20.001;   

// --> rod / pipe diameter along Y axis
rod_diameter_y_mm   = 20.001;   

// --> rod / pipe diameter along Z axis
rod_diameter_z_mm = 20.001;

// --> clearance between rod / pipe and arm
clearance_mm      = 0.25;   

// --> largest diameter arm wall thickness
wall_thickness_mm = 3.5;    

// --> arm length along X axis
length_x_mm = 40.001; 

// --> arm length along Y axis
length_y_mm = 40.001; 

// --> arm length along Z axis
length_z_mm = 40.001; 

// --> angle between arms, measured from X and Z axis
angle_xz = 90; // 90° = vertical
tilt_angle = 90 - angle_xz;

// --> optional reinforcement ribs
extra_strength = true;  // add ribs

// --> rotate and flatten bottom surface for stronger and easier printing
flat_bottom    = false;  

$fn = 120;  // smoothness of curved surfaces
            // Tip:
            // For a tight press-fit reduce clearance.
            // For easier assembly increase clearance.

// ======================================================
// === DERIVED PARAMETERS (do not modify) ===============
// ======================================================

rod_diameter_mm = // largest of the 3 diameters
    (rod_diameter_x_mm > rod_diameter_y_mm)
        ? ((rod_diameter_x_mm > rod_diameter_z_mm) ? rod_diameter_x_mm : rod_diameter_z_mm)
        : ((rod_diameter_y_mm > rod_diameter_z_mm) ? rod_diameter_y_mm : rod_diameter_z_mm);

// inner radii of connector bore        
r_in  = (rod_diameter_mm + clearance_mm) / 2;
r_in_x = (rod_diameter_x_mm + clearance_mm) / 2;
r_in_y = (rod_diameter_y_mm + clearance_mm) / 2;
r_in_z = (rod_diameter_z_mm + clearance_mm) / 2;
// wall thickness
w     = wall_thickness_mm;
// outer radius of connector arm (the same for all)
r_out = r_in + w;

// arms lengths
length_mm = min(length_x_mm, length_y_mm, length_z_mm);
h_x = length_x_mm;
h_y = length_y_mm;
h_z = length_z_mm;
h = length_mm;

// rib geometry
rib_length    = h/3.5;
rib_thickness = h/64.;


// ======================================================
// === GENERIC TUBE ALONG AXIS (+ direction) ============
// Creates a hollow tube along X, Y or Z axis
// ======================================================
module tube_along(axis=[1,0,0], r=10, h=10) {

    rot =
        (axis == [1,0,0]) ? [ 90, 0, 0] :
        (axis == [0,1,0]) ? [  0,90, 0] :
                           [  0, 0, 0];   // default = Z

    rotate(rot)
    difference() {
        cylinder(h=h, r=r_out, center=false);
        translate([0,0,r_out])
            cylinder(h=h, r=r, center=false);
    }
}


// ======================================================
// === GENERIC TUBE ALONG AXIS (− direction) ============
// Same tube but extruded in negative direction
// ======================================================
module tube_along_neg(axis=[0,1,0], r=10, h=10) {

    rot =
        (axis == [1,0,0]) ? [ 90, 0, 0] :
        (axis == [0,1,0]) ? [  0,90, 0] :
                           [  0, 0, 0];

    rotate(rot)
    translate([0,0,-h])
    difference() {
        cylinder(h=h, r=r_out, center=false);
        translate([0,0,-r_out])
            cylinder(h=h, r=r, center=false);
    }
}



// ======================================================
// === MAIN CONNECTOR GEOMETRY ==========================
// Combines four tubes and reinforcement ribs
// ======================================================
module connector4_y() {

    difference() {

        union() {

            // tubes
            tube_along([1,0,0], r_in_y, h_y);      // -Y
            tube_along([0,1,0], r_in_x, h_x);      // +X
            tube_along_neg([1,0,0], r_in_y, h_y);  // +Y   
            rotate([0,tilt_angle,0])
                tube_along([0,0,1], r_in_z, h_z);      // +Z

            // center rounding
            sphere(r=r_out);

            // ==========================
            // ==== RIBS ===
            // ==========================
            if(extra_strength){

                // rib between +X and +Z
                if (tilt_angle <= 40)
                    hull(){
                rotate([0,tilt_angle,0])
                        translate([r_in, 0, r_in+w/2])
                            cylinder(h=rib_length+w/2, r=w/2);
                        translate([rib_length+r_out-w/2, 0, r_in+w/2])
                            cylinder(h=rib_thickness, r=w/2);
                    }

                // rib between +Y and +Z

                rotate([0,tilt_angle,0])
                    hull(){
                        translate([0, r_in+w/2, r_in+w/2])
                            cylinder(h=rib_length, r=w/2);
                        translate([0, rib_length+r_out-w/2, r_in+w/2])
                            cylinder(h=rib_thickness, r=w/2);
                    }

                // rib between -Y and +Z

                rotate([0,tilt_angle,0])
                    hull(){
                        translate([0, -r_in-w/2, r_in+w/2])
                            cylinder(h=rib_length, r=w/2);
                        translate([0, -rib_length-r_out+w/2, r_in+w/2])
                            cylinder(h=rib_thickness, r=w/2);
                    }

                // diagonal rib on +Y side
                hull(){
                    translate([r_in+w/2, r_in+w/2, 0])
                        rotate([0,90,0])
                            cylinder(h=rib_length, r=w/2);
                    translate([r_in+w/2, rib_length+r_out-w/2, 0])
                        rotate([0,90,0])
                            cylinder(h=rib_thickness, r=w/2);
                }

                // diagonal rib on -Y side
                hull(){
                    translate([r_in+w/2, -r_in-w/2, 0])
                        rotate([0,90,0])
                            cylinder(h=rib_length, r=w/2);
                    translate([r_in+w/2, -rib_length-r_out+w/2, 0])
                        rotate([0,90,0])
                            cylinder(h=rib_thickness, r=w/2);
                }
            }
        }

       // bore once more into +X to get rid of rotated XZ rib
        rotate([0,90,0])
        translate([0,0,r_out])
            cylinder(h=h_x, r=r_in_x, center=false);


       // bore once more into +Z to get rid of X tube within bore
       rotate([0,tilt_angle,0])
        translate([0,0,r_out])
            cylinder(h=h_z, r=r_in_z, center=false);
    }
}


// ======================================================
// === FINAL RENDER =====================================
// Applies optional flat bottom cut for easier printing
// ======================================================
module render_connector() {

    if(flat_bottom) {
        difference() {
            translate([0,0,r_out-wall_thickness_mm/3])
                rotate([0,-(tilt_angle/2 + 45),0])
                    connector4_y();

            translate([0,0,-r_out/2])
                cube([h*2,h*2,r_out], center=true);
        }
    } else {
        connector4_y();
    }
}

render_connector();

include <BOSL2/std.scad>;

/**
 * Bearing Generator
 *      
 * Author: Jason Koolman  
 * Version: 1.2  
 *
 * Description:
 * This OpenSCAD script generatses a variety of fully parametric  
 * ball bearings with FDM optimization and customizable options.
 *
 * License:
 * This script licensed under a Standard Digital File License.
 *
 * Changelog:
 * [v1.1]
 * - Added support for 17 more bearing types (F686ZZ-F6006ZZ).
 *
 * [v1.2]
 * - Added support for 5 more bearing type (605 & 16000-series).
 */
    
/* [🛞️️ Bearing] */

// Bearing type (standard sizes or custom).
Type = "6000"; // [custom: ⚙ Custom, R2, R3, R4, R6, R8, R10, R12, R14, R16, R18, R20, R22, R24, 605, 608, 629, 635, 6000, 6001, 6002, 6003, 6007, 6200, 6201, 6202, 6203, 6204, 6205, 6206, 6207, 6208, 6209, 6210, 6211, 6212, 6301, 6302, 6303, 6304, 6305, 6306, 6307, 6308, 6309, 6310, 6311, 6312, 6403, 6800, 6801, 6802, 6803, 6804, 6805, 6806, 6900, 6901, 6902, 6903, 6904, 6905, 6906, 6907, 6908, 16004, 16005, 16100, 16101, F686ZZ, F687ZZ, F688ZZ, F689ZZ, F6900ZZ, F6901ZZ, F6902ZZ, F6903ZZ, F6904ZZ, F6905ZZ, F6000ZZ, F6001ZZ, F6002ZZ, F6003ZZ, F6004ZZ, F6005ZZ, F6006ZZ]

// Rolling element type.
Ball = "dumbbell"; // [ball: Ball, roller: Roller, dumbbell: Dumbbell]

// Spacing between rolling elements.
Spacing = 0.05; // [0:0.01:0.5]

// Extra gap between elements and raceways.
Clearance = 0.15; // [0.05:0.01:0.4]

// Chamfer size for bearing edges.
Chamfer = 0.6;

/* [⚙️ Custom] */

// Inner diameter.
Inner_Diameter = 14;

// Outer diameter.
Outer_Diameter = 28;

// Width of the bearing.
Width = 8;

// Add a flange?
Flange = false;

// Diameter of the flange.
Flange_Diameter = 32;

// Width of the flange.
Flange_Width = 2;

/* [📷 Render] */

// Slice model in half for debugging.
Slice = false;

// Render resolution to control detail level.
Resolution = 2; // [4: Ultra, 3: High, 2: Medium, 1: Low]

// Color of the model.
Color = "#e2dede"; // color

// Determine face angle and size based on resolution
Face = (Resolution == 4) ? [1, 0.1]
    : (Resolution == 3) ? [2, 0.15]
    : (Resolution == 2) ? [2, 0.2]
    : [4, 0.4];

$fa = Face[0];
$fs = Face[1];

/* [Hidden] */

// Render
if (Slice) {
    back_half() generate();
} else {
    generate();
}

module generate() {
    color(Color)
    ball_bearing(Type == "custom" ? undef : str(Type),
        id=Inner_Diameter,
        od=Outer_Diameter,
        width=Width,
        flange=Flange,
        fd=Flange_Diameter,
        fw=Flange_Width,
        clearance=Clearance,
        ball_type=Ball,
        ball_spacing=Spacing,
        chamfer=Chamfer
    );
}

/**
 * Creates a standardized ball bearing assembly.
 *
 * @param   trade_size      Standard ball bearing size (e.g., "608", "R10"). Overrides `id`, `od`, `width`.
 * @param   id              Inner diameter (used if `trade_size` is not set).
 * @param   od              Outer diameter.
 * @param   width           Bearing width.
 * @param   flange          Enables a flanged bearing.
 * @param   fd              Flange diameter (required if `flange = true`).
 * @param   fw              Flange width.
 * @param   chamfer         Chamfer amount for smoother edges.
 * @param   rounding        Rounds inner and outer edges for printability.
 * @param   ball_spacing    Gap factor between balls (0 = touching).
 * @param   ball_type       Type of rolling element.
 * @param   anchor          Positioning anchor (default: `CTR`).
 * @param   spin            Rotation around Z-axis (degrees).
 * @param   orient          Orientation of the bearing (default: `UP`).
 */
module ball_bearing(
    trade_size,
    id, od, width,
    flange = false, fd, fw,
    chamfer, rounding,
    clearance = 0.1,
    ball_type = "ball",
    ball_spacing = 0.05,
    anchor = CTR,
    spin = 0,
    orient = UP
) {
    info = is_undef(trade_size) ? [id, od, width, flange, fd, fw] : ball_bearing_info(trade_size);
    checks =
        assert(all_defined(select(info, 0,4)), "Invalid bearing info supplied")
        assert(ball_spacing >= 0 && ball_spacing <= 0.5, "Invalid spacing supplied");
        
    if (flange) {
        assert(!is_undef(fd), "Flange requires a specified diameter");
        assert(!is_undef(fw), "Flange requires a specified width");
    }
    
    id = info[0];
    od = info[1];
    width = info[2];
    flange = info[3];
    fd = info[4];
    fw = info[5];
    mid_d = (id+od)/2;
    wall = (od-id)/2/3;
    
    ball_d = (wall*2) * (ball_type == "roller" ? 0.95 : ball_type == "dumbbell" ? 0.75 : 1);
    ball_count = floor(PI*mid_d*(1-ball_spacing) / ball_d);
    ball_elevate = (width - ball_d) / 2;
    
    // Generate rolling element shape
    ball_half_shape = [
        for (p = right_half(ball_shape(ball_type, ball_d=ball_d, width=width))[0])
            [max(0, p.x), p.y] // ensure X+ half-plane
    ];
    ball_mask_shape = ball_shape(ball_type, ball_d=ball_d, width=width, clearance=clearance);
    ball_vnf = rotate_sweep(ball_half_shape);
    
    attachable(anchor, spin, orient, d = od, l = width) {
        union() {
            // Bearing structure
            difference() {
                union() {
                    tube(id=id, wall=wall+(ball_type == "dumbbell" ? wall/4 : 0), h=width, irounding=rounding, ichamfer=chamfer);
                    tube(od=od, wall=wall+(ball_type == "dumbbell" ? wall/4 : 0), h=width, orounding1=flange ? undef : rounding, 
                         ochamfer1=flange ? undef : chamfer, orounding2=rounding, ochamfer2=chamfer);
                }
                if (ball_type == "ball") {
                    torus(r_maj = mid_d / 2, r_min = wall + clearance);
                } else {
                    rotate_sweep(right(mid_d / 2, ball_mask_shape));
                }
            }

            // Rolling elements
            for (i = [0 : ball_count - 1]) {
                zrot(i * 360 / ball_count) right(mid_d / 2) {
                    if (ball_type == "ball") {
                        sphere(d = ball_d);
                    } else {
                        vnf_polyhedron(ball_vnf);
                    }
                }
            }

            // Flange support
            if (flange) {
                down(width / 2 - fw / 2)
                    tube(id = od, od = max(od, fd), h = fw, orounding1 = rounding);
            }

            // Ball support structure
            if (ball_type == "ball") {
                down(width / 2)
                difference() {
                    support_h = ball_elevate + 0.12;
                    tube(od = mid_d + wall / 2, id = mid_d - wall / 2, l = support_h, anchor = BOTTOM);
                    zrot(180 / ball_count) right(mid_d / 2)
                        cube([wall, ball_d / 2, support_h + 0.01], anchor = BOTTOM);
                }
            }
        }
        children();
    }
}

/**
 * Generates the rolling element shape for the bearing.
 *
 * @param   type        Type of rolling element: "ball", "roller", "dumbbell".
 * @param   ball_d      Diameter of the rolling element.
 * @param   width       Width of the bearing.
 * @param   clearance   Additional spacing applied to the rolling element.
 * @return  2D shape of the rolling element.
 */
function ball_shape(type, ball_d, width, clearance = 0) =
    type == "roller" ? 
        union(
            rect([ball_d + clearance * 2, width - ball_d/2], chamfer=ball_d/4),
            rect([ball_d + clearance * 2 - (ball_d/4) * 2, width])
        ) :
    type == "dumbbell" ?
        difference(
            rect([ball_d + clearance * 2, width]),
            xflip_copy(p = right(ball_d/2 + clearance, trapezoid(h=ball_d/4, w1=ball_d/3, ang=135, spin=-90, anchor=BACK)))
        ) :
    circle(d = ball_d + clearance * 2);

/**
 * Retrieves size specifications for a standardized ball bearing.
 *
 * @param   trade_size  Standard bearing designation (e.g., "608", "R10").
 * @return  List of parameters: `[id, od, width, flange, flange_diameter, flange_width]`.
 */
function ball_bearing_info(trade_size) =
    assert(is_string(trade_size))
    let(
        IN = 25.4,
        data = [
            // trade_size, ID,     OD,      width,  flanged, fd, fw 
            [      "R2",  1/8*IN,  3/8*IN,  5/32*IN, false,   0,  0 ],
