/* [Flexigrid Options] */

// Shape of the Flexigrid
shape = 0; // [0:Retangle, 1:Heart, 2:Circle, 3:Diamond, 4:Cross, 5:Checker Grid, 36:Animal Face]

// Number of columns
grid_columns = 5; // [2:25]

// Number of rows
