    (rows % 2 == 1 && columns % 2 == 1 && row == (rows - 1) / 2 && column == (columns - 1) / 2) || 
    (rows % 2 == 0 && columns % 2 == 0 && row >= (rows / 2 - 1) && row <= (rows / 2) && column >= (columns / 2 - 1) && column <= (columns / 2)) ||
