 */
module gridfinity_base_lite(grid_size, grid_dimensions=GRID_DIMENSIONS_MM, wall_thickness, bottom_thickness, hole_options=bundle_hole_options(), only_corners = false) {
    assert(is_list(grid_size) && len(grid_size) == 2 && grid_size.x > 0 && grid_size.y > 0);
    assert(is_num(wall_thickness) && wall_thickness > 0);
    assert(is_num(bottom_thickness)
        && bottom_thickness >= 0
        && bottom_thickness <= BASE_HEIGHT);
    assert(is_bool(only_corners));

    wall_thickness_2d = [wall_thickness, wall_thickness];

    solid_bridge_height = bottom_thickness - BASE_PROFILE_HEIGHT;
    profile_height = min(bottom_thickness, BASE_PROFILE_HEIGHT);

    individual_base_size_mm = grid_dimensions - BASE_GAP_MM;
    // Final size of the base top. In mm.
    // Subtracting BASE_GAP_MM to remove the perimeter overhang.
    grid_size_mm = [
        grid_dimensions.x * grid_size.x,
        grid_dimensions.y * grid_size.y
    ] - BASE_GAP_MM;

    //Hollow bridging structure to tie the bases together
    color("RosyBrown")
    difference() {
        _base_bridge_solid(grid_size_mm);

        //Creates a square bridging structure.
        translate([0, 0, BASE_PROFILE_HEIGHT-TOLLERANCE])
        pattern_grid(grid_size, grid_dimensions, true, true)
        linear_extrude(BASE_BRIDGE_HEIGHT+2*TOLLERANCE)
        rounded_square(
            individual_base_size_mm - 2 * wall_thickness_2d,
            BASE_TOP_RADIUS-wall_thickness,
            center=true);

        // Chamfer the inner edges
        translate([0, 0, BASE_PROFILE_HEIGHT-TOLLERANCE])
        intersection() {
            pattern_grid(grid_size, grid_dimensions, true, true)
            _lite_bridge_chamfer(
                individual_base_size_mm,
                wall_thickness);

            // Don't touch the exterior.
            linear_extrude(BASE_BRIDGE_HEIGHT+2*TOLLERANCE)
            rounded_square(
                grid_size_mm- 2 * wall_thickness_2d,
                BASE_TOP_RADIUS-wall_thickness,
                center=true);
        }
    }

    //Solid bridging structure
    if (solid_bridge_height > 0) {
        _base_bridge_solid(grid_size_mm, solid_bridge_height);
    }

    render()
    if(only_corners) {
        difference() {
            union() {
                pattern_grid(grid_size, grid_dimensions, true, true)
                base_outer_shell(wall_thickness, profile_height, individual_base_size_mm);
                _base_holes(hole_options, grid_size_mm, -2*wall_thickness);
            }

            _base_holes(hole_options, grid_size_mm);
            _base_preview_fix();
        }
    }
    else {
        pattern_grid(grid_size, grid_dimensions, true, true) {
            difference() {
                union() {
                    base_outer_shell(wall_thickness, profile_height, individual_base_size_mm);
                    _base_holes(hole_options, individual_base_size_mm, -2*wall_thickness);
                }
                _base_holes(hole_options, individual_base_size_mm);
                _base_preview_fix();
            }
        }
    }
}

/**
 * @brief The solid bridging structure for bases.
 * @details Already translated to the correct height. Per the standard.
 * @param grid_size_mm Total grid size.
 *        Taking BASE_GAP_MM into account.
 * @param height
 */
module _base_bridge_solid(grid_size_mm, height=BASE_BRIDGE_HEIGHT) {
    assert(is_valid_2d(grid_size_mm)
        && is_positive(grid_size_mm));
    assert(is_num(height)
        && height >= 0
        && height <= BASE_BRIDGE_HEIGHT);

    color("RosyBrown")
    translate([0, 0, BASE_PROFILE_HEIGHT])
    linear_extrude(height)
    rounded_square(grid_size_mm, BASE_TOP_RADIUS, center=true);
}

/**
 * @brief Negative to chamfer the bridge structure for lite bases.
 * @param individual_base_size_mm Size of a single base.
 *        Taking BASE_GAP_MM into account.
 * @param wall_thickness
 */
module _lite_bridge_chamfer(individual_base_size_mm, wall_thickness) {
    assert(is_valid_2d(individual_base_size_mm)
        && is_positive(individual_base_size_mm));
    assert(is_num(wall_thickness)
        && wall_thickness > 0);

    chamfer_polygon = [
        [0, 0], // Inside of bin
        [wall_thickness, BASE_BRIDGE_HEIGHT],
        [0, BASE_BRIDGE_HEIGHT],
    ];
    translated_polygon = foreach_add(
        chamfer_polygon, [
            BASE_TOP_RADIUS-wall_thickness-TOLLERANCE,
            2*TOLLERANCE
        ]);
    sweep_inner = individual_base_size_mm
        - 2 * [BASE_TOP_RADIUS, BASE_TOP_RADIUS];

    sweep_rounded(sweep_inner)
    polygon(translated_polygon);
}

/**
 * @brief Solid polygon of a gridfinity base.
 * @details Ready for use with `sweep_rounded(...)`.
 *          Square internals allow for `cube` to fill the center.
 */
module _base_polygon() {
    translated_line = foreach_add(BASE_PROFILE, [BASE_BOTTOM_RADIUS, 0]);
    solid_profile = concat(translated_line,
        [
            [0, BASE_PROFILE_HEIGHT],  // Go in to form a solid polygon
            [0, 0],  // Needed since start has been translated.
        ]
    );
    polygon(solid_profile);
}

/**
 * @brief A single solid Gridfinity base.
 * @details Height is BASE_PROFILE_HEIGHT.
 * @warning Does not include the structure tying the bases together.
 * @param top_dimensions [x, y] size of a single base.  Only set if deviating from the standard!
 */
module base_solid(top_dimensions=BASE_TOP_DIMENSIONS) {
    assert(is_valid_2d(top_dimensions)
           && min(top_dimensions) > 2 * BASE_TOP_RADIUS,
        str("Minimum size of a single base must be greater than ", 2 * BASE_TOP_RADIUS)
    );

    base_bottom = base_bottom_dimensions(top_dimensions);
    sweep_inner = foreach_add(base_bottom, -2*BASE_BOTTOM_RADIUS);
    cube_size = foreach_add(base_bottom, -BASE_BOTTOM_RADIUS);

    union(){
        sweep_rounded(sweep_inner)
        _base_polygon();

        //Inner fill
        translate([0, 0, BASE_PROFILE_HEIGHT/2])
        cube([cube_size.x, cube_size.y, BASE_PROFILE_HEIGHT], center=true);
    }
}

/**
 * @brief Internal function to create the negative for a Gridfinity Refined thumbscrew hole.
 * @details Magic constants are what the threads.ScrewHole function does.
 */
module _base_thumbscrew() {
    ScrewThread(
        1.01 * BASE_THUMBSCREW_OUTER_DIAMETER + 1.25 * 0.4,
        BASE_PROFILE_HEIGHT,
        BASE_THUMBSCREW_PITCH
    );
}

/**
 * @brief Internal Code. Generates the 4 holes for a single base.
 * @details Need this fancy code to support refined holes and non-square bases.
 * @param top_dimensions [length, width] of a single Gridfinity base.
 * @param hole_options @see bundle_hole_options
 * @param offset @see block_base_hole.offset
 */
module _base_holes(hole_options, top_dimensions=BASE_TOP_DIMENSIONS, offset=0) {
    hole_position = foreach_add(
        base_bottom_dimensions(top_dimensions)/2,
        -HOLE_DISTANCE_FROM_BOTTOM_EDGE
    );

    for(a=[0:90:270]){
        // i and j represent the 4 quadrants.
        // The +1 is used to keep any values from being exactly 0.
        j = sign(sin(a+1));
        i = sign(cos(a+1));
        translate([i * hole_position.x, j * hole_position.y, 0])
        rotate([0, 0, a])
        block_base_hole(hole_options, offset);
    }
}

/**
 * @brief A single Gridfinity base.  With holes (if set).
 * @details Height is BASE_PROFILE_HEIGHT.
 * @param hole_options @see block_base_hole.hole_options
 * @param top_dimensions [x, y] size of a single base.  Only set if deviating from the standard!
 * @param thumbscrew Enable "gridfinity-refined" thumbscrew hole in the center of each base unit. This is a ISO Metric Profile, 15.0mm size, M15x1.5 designation.
 */
module block_base(hole_options, top_dimensions=BASE_TOP_DIMENSIONS, thumbscrew=false) {
    assert(is_valid_2d(top_dimensions) && is_positive(top_dimensions));
    assert(is_bool(thumbscrew));

    base_bottom = base_bottom_dimensions(top_dimensions);

    difference() {
        base_solid(top_dimensions);

        if (thumbscrew) {
            _base_thumbscrew();
        }
        _base_holes(hole_options, top_dimensions);
        _base_preview_fix();
    }
}

/**
 * @brief Outer shell of a Gridfinity base.
 * @details Height is BASE_PROFILE_HEIGHT.
 * @param wall_thickness How thick the walls are.
 *                       Capped at BASE_TOP_RADIUS.
 * @param bottom_thickness How thick the bottom is.
 * @param top_dimensions [x, y] size of a single base.  Only set if deviating from the standard!
 * @IMPORTANT: This is highly optimized to reduce the amount of geometry generated.
 */
module base_outer_shell(wall_thickness, bottom_thickness, top_dimensions=BASE_TOP_DIMENSIONS) {
    assert(is_num(wall_thickness) && wall_thickness > 0);
    assert(is_num(bottom_thickness)
        && bottom_thickness >= 0
        && bottom_thickness <= BASE_PROFILE_HEIGHT);
    assert(is_valid_2d(top_dimensions)
           && min(top_dimensions) > 2 * BASE_TOP_RADIUS,
        str("Minimum size of a single base must be greater than ", 2 * BASE_TOP_RADIUS)
    );

    base_bottom = base_bottom_dimensions(top_dimensions);
    sweep_inner = foreach_add(base_bottom, -2*BASE_BOTTOM_RADIUS);
    cube_size = foreach_add(base_bottom, -BASE_BOTTOM_RADIUS);

    optimized_wall = wall_thickness <= BASE_BOTTOM_RADIUS;
    optimized_bottom = optimized_wall
        || bottom_thickness < (wall_thickness - BASE_BOTTOM_RADIUS);

    if(_debug)
        echo(
            optimized_wall=optimized_wall,
            optimized_bottom=optimized_bottom
        );

    union(){
        //Sides
        if(optimized_wall) {
            sweep_rounded(sweep_inner)
            _base_polygon_lite(wall_thickness, bottom_thickness);
        } else {
            sweep_rounded(sweep_inner)
            difference() {
                _base_polygon();

                translate([-wall_thickness, 0, 0])
                _base_polygon();
            }
        }

        //Bottom
        if (bottom_thickness > 0)
        if(optimized_bottom){
            translate([0, 0, bottom_thickness/2])
            cube(concat(cube_size, bottom_thickness), center=true);
        } else {
            intersection() {
                translate([0, 0, bottom_thickness/2])
                cube(concat(top_dimensions, bottom_thickness), center=true);
                base_solid(top_dimensions=top_dimensions);
            }
        }
    }
}

/**
 * @brief Optimized lite version of `_base_polygon`.
 * @details Ready for use with `sweep_rounded(...)`.
 *          Produces a shape with a specific thickness.
 *          Bottom internals are squared for use with `cube`.
 * @param wall_thickness How thick the resulting walls are.
 *        Max allowed is BASE_BOTTOM_RADIUS.
 * @param bottom_thickness How thick the bottom is.
 *        Max allowed is BASE_PROFILE_HEIGHT.
 * @warning: Walls may be slightly thicker than expected as they slope to the appropriate bottom_thickness.
 */
module _base_polygon_lite(wall_thickness, bottom_thickness) {
    assert(is_num(wall_thickness)
        && wall_thickness > 0
        && wall_thickness <= BASE_BOTTOM_RADIUS);
    assert(is_num(bottom_thickness)
        && bottom_thickness >= 0
        && bottom_thickness <= BASE_PROFILE_HEIGHT);

    translated_line = foreach_add(BASE_PROFILE, [BASE_BOTTOM_RADIUS, 0]);
    inner_line = reverse(
        foreach_add(translated_line, [-wall_thickness, 0])
    );

    first_point = inner_line[0];
    last_point = inner_line[len(inner_line) -1];

    // Ensures the end is squared off.
    capped_inner_line = [
        for(p = inner_line)
            [p.x, max(p.y, bottom_thickness)]
    ];

    solid_profile = concat(
        translated_line,
        capped_inner_line,
        [last_point] // Go back to start.
    );
    polygon(solid_profile);
}

/**
 * @brief Internal code.  Fix base preview rendering issues.
 * @details Preview does not like perfect top/bottoms.
 */
module _base_preview_fix() {
    if($preview){
        cube([10000, 10000, 0.01], center=true);
        translate([0, 0, BASE_PROFILE_HEIGHT])
        cube([10000, 10000, 0.01], center=true);
    }
}

/**
 * @file
 * @brief Functions to create a Gridfinty bin, and cutouts in said bin.
 * @details Uses a struct like syntax to avoid globals.
 * @example ```
 *     bin1 = new_bin(...)
 *     bin_render(bin1) {
 *       bin_subdivide(bin1, [x_divisions, y_divisions]) {
 *         ...
 *       }
 *     }
 * ```
 */

include <standard.scad>
use <base.scad>
use <gridfinity-rebuilt-holes.scad>
use <wall.scad>
use <../helpers/grid.scad>
use <../helpers/grid_element.scad>
use <../helpers/generic-helpers.scad>
use <../helpers/list.scad>
use <../helpers/shapes.scad>

/*
 * @brief Initialize A Gridfinity Bin
 * @details Creates the top portion of a bin, and sets some gloal variables.
 * @param grid_size Size in number of bases. [x, y]
 * @param height_mm Bin height in mm.
 *                  Excludes STACKING_LIP_HEIGHT.
 *                  Includes BASE_HEIGHT.
 * @param fill_height_mm Height of the solid which fills a bin.  In mm.
          Set to 0 for automatic.
          Negative numbers are subtracted from the height.
          Set to -height_mm for no infill.
 * @param include_lip If the bin should have a stacking lip.
 * @param hole_options @see bundle_hole_options
 * @param only_corners If only the outer corners of the bin should have holes.
 * @param thumbscrew If the bin's base should have a thumbscrew hole.
 * @param grid_dimensions [length, width] of a single Gridfinity base.
 * @param base_thickness Lower this to create a "lite" bin with a hollow base.
 */
function new_bin(
        grid_size,
        height_mm,
        fill_height = 0,
        include_lip = true,
        hole_options=bundle_hole_options(),
        only_corners=false,
        thumbscrew=false,
        grid_dimensions = GRID_DIMENSIONS_MM,
        base_thickness = BASE_HEIGHT
    ) =
    assert(is_valid_2d(grid_size) && is_positive(grid_size))
    assert(is_num(height_mm) && height_mm >= BASE_HEIGHT)
    assert(is_num(fill_height))
    assert(is_bool(include_lip))
    assert(is_hole_options(hole_options))
    assert(is_bool(only_corners))
    assert(is_bool(thumbscrew))
    assert(is_valid_2d(grid_dimensions) && is_positive(grid_dimensions))
    assert(is_num(base_thickness)
        && base_thickness >= 0
        && base_thickness <= BASE_HEIGHT)
    assert(thumbscrew == false
        || base_thickness == BASE_HEIGHT,
        "Thumscrews are not compatible with custom base_thickness.")
    assert(!include_lip
        || fill_height <= 0
        || fill_height <= height_mm - STACKING_LIP_SUPPORT_HEIGHT,
        str("Maximum fill_height for this bin is", height_mm - STACKING_LIP_SUPPORT_HEIGHT))
    let(fill_height_calculated = include_lip ?
        height_mm - BASE_HEIGHT - STACKING_LIP_SUPPORT_HEIGHT
        : height_mm - BASE_HEIGHT)
    let(fill_height_real =
        fill_height > 0 ? fill_height
        : fill_height_calculated + fill_height
    )
    // Subtracting BASE_GAP_MM to remove the perimeter overhang.
    let(base_grid=new_grid(
        concat(as_2d(grid_size), 1),
        concat(as_2d(grid_dimensions), height_mm),
        true,
        _BIN_BASE_GAP_MM_PERIMETER)
    )
    [
        "gridfinity_bin_struct",
        base_grid,
        base_thickness,
        fill_height_real,
        include_lip,
        undef,
        undef,
        undef,
        hole_options,
        only_corners,
        thumbscrew
    ];

/*
 * @brief Render a solid bin.
 * @details Any children are subtracted from the bin.
 *          Automatically translated so [0, 0, 0] is the center of the bin, at the top of the fill.
 *     Stacking lip guards are always in place.
 * @warning Stacking lip guards may be removed in the future.
 * @param bin The bin to render.  Created by `new_bin`.
 * @param enable_guards Prevent infill from cutting into the base.
 *     In general, ajust `new_bin(base_thickness=...)` instead.
 */
module bin_render(bin, enable_guards=true) {
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    );
    assert(is_bool(enable_guards));
    fill_height = max(bin[3], 0);
    include_lip = bin[4];

    // If no lip is present, the outer wall is handled by the infill.
    if (include_lip) {
        bin_render_wall(bin);
    }

    // While not required, lite bases will not show correctly in preview without this.
    render()
    difference() {
        union() {
            bin_render_infill(bin);
            if(!enable_guards)
                bin_render_base(bin);
        }
        translate([0, 0, BASE_HEIGHT + fill_height + TOLLERANCE])
        children();
    }
    if(enable_guards)
        bin_render_base(bin);
}

/**
 * @brief Render the inner solid part of a bin.
 * @details The resulting solid intersects with the walls.
 *          Allowing a bin without a stacking lip to have a wall.
 * @param bin The bin to render.  Created by `new_bin`.
 */
module bin_render_infill(bin) {
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    );
    base_grid = bin[1];
    base_thickness = bin[2];
    fill_height = bin[3];  //May be negative.
    hole_options = bin[8];
    only_corners = bin[9];
    thumbscrew = bin[10];

    grid_size_mm = as_2d(grid_get_total_dimensions(base_grid));
    grid_size = bin_get_bases(bin);
    grid_dimensions = bin_get_grid_dimensions(bin);

    color("firebrick")
    translate([0, 0, BASE_HEIGHT])
    linear_extrude(max(fill_height, 0))
    rounded_square(
        grid_size_mm - [TOLLERANCE, TOLLERANCE],
        BASE_TOP_RADIUS,
        center=true);

    // "lite" bins can use the base as infill.
    if(base_thickness != BASE_HEIGHT) {
        total_fill_height = bin_get_infill_size_mm(bin).z;
        intersection() {
            translate([0, 0, base_thickness])
            linear_extrude(total_fill_height)
            square(grid_size_mm, center=true);

            color("firebrick")
            gridfinityBase(grid_size,
                grid_dimensions=grid_dimensions,
                hole_options=hole_options,
                only_corners=only_corners,
                thumbscrew=thumbscrew);
        }
    }
}

/**
 * @brief Render the wall of a bin.  With a stacking lip.
 * @param bin The bin to render.  Created by `new_bin`.
 * @see bin_render_infill if you do not want a stacking lip.
 */
module bin_render_wall(bin) {
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    );
    let(base_grid = bin[1])
    let(wall_height = grid_get_total_dimensions(base_grid)
        - [0, 0, BASE_HEIGHT])

    translate([0, 0, BASE_HEIGHT])
    render_wall(wall_height);
}

/**
 * @brief Render the base of a bin.
 * @param bin The bin to render.  Created by `new_bin`.
 */
module bin_render_base(bin) {
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    );
    base_thickness = bin[2];
    hole_options = bin[8];
    only_corners = bin[9];
    thumbscrew = bin[10];

    grid_size = bin_get_bases(bin);
    grid_dimensions = bin_get_grid_dimensions(bin);

    if(base_thickness == BASE_HEIGHT) {
        gridfinityBase(grid_size,
            grid_dimensions=grid_dimensions,
            hole_options=hole_options,
            only_corners=only_corners,
            thumbscrew=thumbscrew);
    } else {
        gridfinity_base_lite(grid_size,
            grid_dimensions=grid_dimensions,
            wall_thickness=d_wall,
            bottom_thickness=base_thickness,
            hole_options=hole_options,
            only_corners=only_corners);
    }
}

/**
 * @brief Subdivide the bin.  Any children will be cut out from the center of each sub-division.
 * @details Supports `grid_element_current`.
 *          Takes wall thickness into account.
 *          Meaning `bin_subdivide(bin, bin_bin_get_bases(bin))` does **not** exactly correspond to the center of each base!
 *          Does nothing if there is no infill.
 * @param bin A bin created by the `new_bin` function.
 * @param subdivisions The number of sub bins/shapes to cut into the bin. [x, y]
 * @see bin_get_infill_size_mm For why wall thickness needs to be subtracted.
 */
module bin_subdivide(bin, subdivisions) {
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    );
    assert(is_valid_2d(subdivisions)
        && subdivisions.x >= 0
        && subdivisions.y >= 0
        );

    num_elements = concat(as_2d(subdivisions), 1);
    infill_size_mm = bin_get_infill_size_mm(bin);

    if(infill_size_mm.z > 0) {
        grid = grid_from_total(num_elements, infill_size_mm, true);
        grid_foreach(grid, true) {
            children();
        }
    }
}

/**
 * @brief Translate to the lower left of a particular grid element.
 * @details [0, 0] is the lower left corner.
 *          Since some functions expect all grid elements to be identical...
 * @param bin A bin created by the `new_bin` function.
 * @param index [x, y] Suppports fractional values.
 * @param exact If [0.5, 0.5] corresponds exactly to the center of a base.
 *        Do not enable this unless you are familiar with how grid_elements interact with perimiters.
 */
module bin_translate(bin, index, exact=false) {
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    );
    assert(is_valid_2d(index));

    index_3d = concat(as_2d(index), 0.5);
    infill_grid = _bin_get_infill_grid(bin, exact);

    grid_translate(infill_grid, index_3d, false)
    children();
}

/**
 * @brief Get the number of bases the bin is composed of.
 * @warning Total size **is not merely multiplying this by `bin_get_bases`.
 * @param bin A bin created by the `new_bin` function.
 * @returns [x, y] Number of bases.
 */
function bin_get_bases(bin) =
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    )
    let(base_grid = bin[1])
    as_2d(grid_get_num_elements(base_grid));

/**
 * @brief Get the dimensions of a single Gridfinity base.
 * @warning Total size **is not merely multiplying this by `bin_get_bases`.
 * @param bin A bin created by the `new_bin` function.
 * @returns [x, y] Size of a single base.
 */
 function bin_get_grid_dimensions(bin) =
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    )
    let(base_grid = bin[1])
    as_2d(grid_get_element_dimensions(base_grid));

/**
 * @brief Get the outer size of the bin.
 * @details Includes base and stacking lip (if enabled).
 * @param bin A bin created by the `new_bin` function.
 * @returns A 3d vector.
 */
function bin_get_bounding_box(bin) =
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    )
    let(base_grid = bin[1])
    let(include_lip = bin[4])
    grid_get_total_dimensions(base_grid)
        + [0, 0, include_lip ? stacking_lip_height() : 0];

/**
 * @brief Get infill dimensions that do not overlap with the walls.
 * @details Wall overlap handling is cricital for cutout chamfers to work correctly.
 * @param bin A bin created by the `new_bin` function.
 * @returns Infill [width, length, height]
 */
function bin_get_infill_size_mm(bin) =
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    )
    let(base_grid = bin[1])
    let(base_thickness=bin[2])
    let(fill_height=bin[3])  //May be negative.
    let(fill_height_total=max(
        fill_height + BASE_HEIGHT - base_thickness, 0))
    let(size_2d=as_2d(grid_get_total_dimensions(base_grid)))
    concat(size_2d-2*[d_wall,d_wall], fill_height_total);

/**
 * @brief Detailed information on bin's overall height.
 * @details Designed for use with `pprint`.
 * @returns A list of [key, value] pairs.
 */
function bin_get_height_breakdown(bin) =
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    )
    let(base_grid = bin[1])
    let(include_lip = bin[4])
    let(bin_height = grid_get_total_dimensions(base_grid).z)
    let(infill_height = bin_get_infill_size_mm(bin).z)
    let(total_height = bin_height + (include_lip ? stacking_lip_height() : 0))
    let(center_height = bin_height - BASE_HEIGHT)
    let(free_space = center_height - infill_height - (include_lip ? STACKING_LIP_SUPPORT_HEIGHT : 0))

    let(heights = [
        ["Total: ", total_height],
        ["* BASE_HEIGHT", BASE_HEIGHT],
        ["  -> BASE_PROFILE_HEIGHT", BASE_PROFILE_HEIGHT],
        ["  -> BASE_BRIDGE_HEIGHT", BASE_BRIDGE_HEIGHT],
        ["* Bin Height", center_height],
        ["  -> Infill", infill_height],
        ["  -> Free space", abs(free_space) > 0.01 ? free_space : 0],
        ["  -> Stacking Lip Support", STACKING_LIP_SUPPORT_HEIGHT],
        ["* Stacking Lip Height (Actual)", stacking_lip_height()],
        ["  -> Stacking Lip Height (Nominal)", STACKING_LIP_HEIGHT],
        ["  -> Stacking Lip Chamfer", stacking_lip_height()-STACKING_LIP_HEIGHT],
    ])

    assert(heights[1][1] == heights[2][1] + heights[3][1],
        "BASE_HEIGHT Calculation Error!")
    assert(heights[8][1] == heights[9][1] + heights[10][1],
        "Stacking Lip Height Calculation Error!")
    assert((heights[5][1] + heights[6][1]
            + (include_lip ? heights[7][1] : 0)
        ) - heights[4][1] < 0.01,
        str("Bin Height Calculation Error!\n",
        "  Expected: ", heights[4][1], "==", heights[5][1],
        "+", heights[6][1], "+", (include_lip ? heights[7][1] : 0),
        "\n"))
    assert(heights[0][1] == heights[1][1] + heights[4][1]
        + (include_lip ? heights[8][1] : 0),
        "Total Height Calculation Error!")
    assert(heights[0][1] == bin_get_bounding_box(bin).z,
        "Total Height Calculation Error!")
    include_lip ? heights: as_list(heights, 7);

/**
 * @brief If the object is a Gridfinity bin.
 * @param bin The object to check.
 */
function is_bin(bin) =
    is_list(bin) && bin[0] == "gridfinity_bin_struct";

/**
 * @brief Internal function. Do not use directly.
 * @param bin A bin created by the `new_bin` function.
 * @param exact If the element center of each element should exactly match the center of the corresponding Gridfinity base.
 * @details Setting exact to true. allows for perfect alignment, but at the cost of the outer elements being slightly smaller.
 */
function _bin_get_infill_grid(bin, exact) =
    assert(is_bin(bin),
        "Not a Gridfinity bin."
    )
    assert(is_bool(exact))
    let(base_grid = bin[1])

    let(infill_size_mm = bin_get_infill_size_mm(bin))
    let(base_perimeter = grid_get_perimeter(base_grid))
    let(infill_element_dimensions=concat(
        bin_get_grid_dimensions(bin),
        infill_size_mm.z))
    let(equal_grid = grid_from_total(
        concat(bin_get_bases(bin), 1), infill_size_mm, true))
    let(exact_grid = grid_from_other(base_grid,
        element_dimensions = infill_element_dimensions,
        perimeter = base_perimeter + _BIN_WALL_PERIMITER))
    // Ensure the calculations are correct.
    assert(grid_get_total_dimensions(equal_grid) == infill_size_mm)
    assert(grid_get_total_dimensions(exact_grid) == infill_size_mm)
    let(infill_grid = exact ? exact_grid : equal_grid)
    infill_grid;

/**
 * @brief Internal variable. Do not use directly.
 */
_BIN_BASE_GAP_MM_PERIMETER = [
    BASE_GAP_MM.x/2,
    BASE_GAP_MM.y/2,
    0,
    BASE_GAP_MM.x/2,
    BASE_GAP_MM.y/2,
    0
];

/**
 * @brief Internal variable. Do not use directly.
 */
 _BIN_WALL_PERIMITER = [
    d_wall,
    d_wall,
    0,
    d_wall,
    d_wall,
    0
 ];

/**
 * @file
 * @brief Modules to cut shapes out of a bin.
 */

include <standard.scad>
use <tab.scad>
use <../helpers/shapes.scad>
use <../helpers/list.scad>
use <../helpers/generic-helpers.scad>
use <../helpers/grid.scad>
use <../helpers/grid_element.scad>

/**
 * @brief "Cutout Grid Scale". Scale [x, y] by the current grid.
 * @details Height is set by the current grid element by default.
 *          Applies `-d_div/2` to X and Y.
 *          **Average element size is not the same as the current element size!**
 * @param size [x, y] in current grid units. z is optional.
 * @param height Override the default height.
 *               If negative, subtract from z-grid height.
 * @return A 3d vector. With z (by default) equal to z-grid (infill) height.
 * @warning Will throw if `grid_element_current()` is not valid.
 */
 function cgs(size=[1, 1], height=0) =
    assert(is_valid_2d(size) && is_positive(size))
    assert(is_num(height))
    let(element=grid_element_current())
    let(grid=grid_element_get_grid(element))
    let(scaled = grid_scale(grid, size))
    assert(is_valid_3d(scaled),
        "grid_element_current() must have at least 3 dimensions.")
    let(divider_mm = [d_div/2, d_div/2, 0])
    let(calculated = as_3d(scaled) - divider_mm)
    assert(calculated.x > 0
        && calculated.y > 0
        && (calculated.z > 0 || height > 0),
        str("Grid Elements too small.  Must be greater than [d_div/2, d_div/2, 0] (", divider_mm, "mm)."))
    [
        calculated.x,
        calculated.y,
        height > 0 ? height : calculated.z + height
    ];

/**
 * @brief A negative of a square compartment with rounded edges,
 *        a chamfered bottom, an optional scoop, and an optional tab.
 * @details Zero position is always the top, with the cutout extending down.
 * @param size_mm [x, y, z] Size of the compartment. In mm.
 * @param scoop_percent 0.0-1.0 How much of a scoop should be present.
 * @param tab_width How wide the tab should be.
 *                  Set to 0 to disable tab.
 * @param tab_angle Determines where the tab is placed.
 *        This will be normalized.
 *        Regardless of compartment dimensions, corners are always at 45 degree intervals.
 *        0: centered +x
 *        46: +y wall, right edge.
 *        90: centered +y
 *        134: +y wall, left edge.
 * @param center_top Default true, cutter [x, y] is centered on the current position.
 *        If false, cutter is in quadrant 1 [+x, +y].
 */
module compartment_cutter(size_mm, scoop_percent=0, tab_width=0, tab_angle=90, center_top=true) {
    assert(is_valid_3d(size_mm) && is_positive(size_mm));
    assert(is_num(scoop_percent));
    assert(is_num(tab_angle)
        || (is_undef(tab_angle) && tab_width == 0));
    assert(is_bool(center_top));

    translate_by = center_top ? [0, 0, 0]
        : [size_mm.x/2, size_mm.y/2, 0];

    color("olive")
    translate(translate_by)
    difference() {
        _half_rounded_square(size_mm);

        if (scoop_percent > 0) {
            _compartment_scoop(
                size_mm+as_3d(TOLLERANCE),
                scoop_percent);
        }

        if (tab_width > 0) {
            _compartment_tab(
                size_mm+as_3d(TOLLERANCE),
                tab_width+TOLLERANCE,
                tab_angle);
        }
    }
}

/**
 * @brief Internal module. Do not use directly.
 * @param size_mm [x, y, z] Size of the compartment. In mm.
 */
module _half_rounded_square(size_mm) {
    assert(is_valid_3d(size_mm)
        && is_positive(size_mm));

    difference(){
        rounded_cube([
            size_mm.x,
            size_mm.y,
            size_mm.z*2,
        ], r_f2, center=true);

        translate([0, 0, size_mm.z/2])
        cube(size_mm+as_3d(TOLLERANCE), center=true);
    }
}

/**
 * @brief Internal module. Do not use directly.
 * @details Add a tab to `cut_compartment`
 * @param size_mm [x, y, z] Size of the compartment. In mm.
 * @param tab_width How wide the tab should be.
 * @param tab_angle Determines where the tab is placed.
 *                  This will be normalized.
 *                  Regardless of compartment dimensions, corners are always at 45 degree intervals.
 */
module _compartment_tab(size_mm, tab_width, tab_angle) {
    assert(is_valid_2d(size_mm) && is_positive(size_mm));
    assert(is_num(tab_angle));
    assert(is_num(tab_width) && tab_width > 0);

    size_2d = as_2d(size_mm);
    normalized_angle = normalize_to_box(size_2d, tab_angle);

    snap_to_edge(size_2d, normalized_angle, tab_width)
    translate([0, 0, -TAB_SIZE.y])
    tab(tab_width);
}

/**
 * @brief Internal module. Do not use directly.
 * @details Add a scoop to `cut_compartment`
 * @param size_mm [x, y, z] Size of the compartment. In mm.
 * @param scoop_percent 0.0-1.0 how of a scoop should be present.
 */
module _compartment_scoop(size_mm, scoop_percent) {
    assert(is_list(size_mm) && len(size_mm) == 3 && size_mm.x >0 && size_mm.y > 0 && size_mm.z > 0);
    assert(is_num(scoop_percent) && scoop_percent > 0.0 && scoop_percent <= 1.0);

    scoop = scoop_percent * size_mm.z/2;

    translate([
        -size_mm.x/2,
        -size_mm.y/2,
        0
    ])
    rotate([0, 90, 0])
    linear_extrude(size_mm.x)
    intersection() {
        // Limit to the compartment's size.
        square([size_mm.z, size_mm.y]);

        difference() {
            translate([size_mm.z, 0])
            mirror([1, 0])
            square(scoop);

            translate([size_mm.z-scoop, scoop])
            circle(scoop);
        }
    }
}

/**
 * @brief Support legacy syntax and options.
 * @details See `compartment_cutter`
 * @param size_mm [x, y, z] Size of the compartment. In mm.
 * @param style_tab [0:Full,1:Auto,2:Left,3:Center,4:Right,5:None]
 *        Auto is not supported if `grid_element_current` is not available.
 * @param tab_top_left_only If the tab will only be on the top left compartment.
 *        Only false is supported when `grid_element_current` is not available.
 * @param scoop 0.0-1.0 How much of a scoop should be present.
 */
module cut_compartment_auto(size_mm, style_tab=5, tab_top_left_only=false, scoop_percent=0) {

    // Lambda so `grid_element_current()` is only called when needed.
    // It can throw!
    is_top_left = function()
        let(element = grid_element_current())
        grid_element_is_last_row(element)
        && grid_element_is_first_col(element);

    has_tab = style_tab != 5 && (!tab_top_left_only || is_top_left());
    tab_width = !has_tab ? 0
        : style_tab == 0 ? max(size_mm) : TAB_WIDTH_NOMINAL;
    tab_angle = has_tab ? get_tab_angle(style_tab) : 0;

    compartment_cutter(size_mm, scoop_percent, tab_width, tab_angle);
}

/**
 * @brief A negative of a chamfered cylinder.  Ready to be cut from solid bin.
 * @details Always a 45 degree chamfer.
 *          A cylinder of `radius+chamfer_radius` can be cut from the walls by default as well.
 * @param radius Radius of the cylinder.
 * @param depth How deep the cylinder goes.
 * @param chamfer_radius How far out from the cylinder, the chamfer should extend.
 * @param cut_lip Add an upper cylinder for cutting the stacking lip.
 *                NOTE: This does not bypass safety measures.
 */
module cut_chamfered_cylinder(radius, depth, chamfer_radius = 0, cut_lip=false) {
    assert(is_num(radius) && radius > 0);
    assert(is_num(depth) && depth > 0);
    assert(is_num(chamfer_radius) && chamfer_radius >= 0);
    outer_radius = radius + chamfer_radius;

    color("olive")
    union() {
        translate([0, 0, -depth])
        cylinder(h=depth, r=radius);

        if (cut_lip) {
            //Taller than tallest bin size.
            cylinder(h=10000, r=outer_radius);
        }

       if (chamfer_radius > 0) {
            mirror([0, 0, 1])
            cone(outer_radius, 45, depth);
        }
    }
}

$test_cutouts=true;
if($test_cutouts) {
    $fa = 4;
    $fs = 0.25;

    dim = [45, 20, 25];

    // Internal - Raw Functions
    translate([0, 50, 0]) {
        _half_rounded_square(dim);

        translate([100, 0, 0])
        _compartment_scoop(dim, 1);
        translate([50, 0, 0])
        difference() {
            _half_rounded_square(dim);
            _compartment_scoop(dim+as_3d(TOLLERANCE), 1);
        }
        translate([-100, 0, 0])
        _compartment_tab(dim, TAB_WIDTH_NOMINAL, 90);
        translate([-50, 0, 0])
        difference() {
            _half_rounded_square(dim);
            _compartment_tab(dim+as_3d(TOLLERANCE),
                TAB_WIDTH_NOMINAL, 90);
        }
    }

    // New Syntax
    compartment_cutter(dim);

    translate([50, 0, 0])
    compartment_cutter(dim, 1);
    translate([-50, 0, 0])
    compartment_cutter(dim, 0, TAB_WIDTH_NOMINAL);
    translate([-100, 0, 0])
    compartment_cutter(dim, 1, TAB_WIDTH_NOMINAL);

    // Support legacy syntax
    translate([0, -50, 0]) {
        cut_compartment_auto(dim);
        translate([50, 0, 0])
        cut_compartment_auto(dim, scoop_percent=1);
        translate([-50, 0, 0])
        cut_compartment_auto(dim, style_tab=3);
        translate([-100, 0, 0])
        cut_compartment_auto(dim, style_tab=3, scoop_percent=1);
    }
    // New Syntax - All tab styles (Except Auto)
    translate([0, -100, 0]) {
        compartment_cutter(dim, 0, 0, 0);
        //Right
        translate([50, 0, 0])
        compartment_cutter(dim, 0, TAB_WIDTH_NOMINAL, 46);
        //Left
        translate([-50, 0, 0])
        compartment_cutter(dim, 0, TAB_WIDTH_NOMINAL, 134);
        // Center
        translate([100, 0, 0])
        compartment_cutter(dim, 0, TAB_WIDTH_NOMINAL, 90);
        // Center (full width)
        translate([-100, 0, 0])
        compartment_cutter(dim, 0, max(dim), 90);
    }
    // Legacy Syntax - All tab styles (Except Auto)
    translate([0, -150, 0]) {
        cut_compartment_auto(dim, style_tab=5);
        //Right
        translate([50, 0, 0])
        cut_compartment_auto(dim, style_tab=4);
        //Left
        translate([-50, 0, 0])
        cut_compartment_auto(dim, style_tab=2);
        // Center
        translate([100, 0, 0])
        cut_compartment_auto(dim, style_tab=3);
        // Center (full width)
        translate([-100, 0, 0])
        cut_compartment_auto(dim, style_tab=0);
    }
    // New Syntax - Centered vs top bottom left
    translate([0, 100, 0]) {
