    translate([0, 0, extra_height])
        rotate([angle, 0, 0])
            // Cap base shape. Constructed top to bottom.
            union() {
                // Tube insert part.
                translate([0, 0, bottomHeight - nothing])
                    difference() {
                        cylinder(r = outerDiameter / 2, h = height);
                        translate ([0, 0, 0.3 * height]) 
                            cylinder(r = innerDiameter / 2, h = height + nothing) ;  
                    };

                // Lead-in for press-fit ridges.
                for (i = [0 : ridgeCount]) {
                    rotate([0, 0, (360 / ridgeCount) * i])
                    translate([outerDiameter / 2, 0, bottomHeight + 0.8 * height - nothing])
                        cylinder(r1 = ridge, r2 = nothing, h = 0.2 * height);
                }

                // Press-fit ridges.
                for (i = [0 : ridgeCount]) {
                    rotate([0, 0, (360 / ridgeCount) * i])
                    translate([outerDiameter / 2, 0, bottomHeight])
                        cylinder(r = ridge, h = 0.8 * height);
                }

                // Cylindrical cap part.
                translate([0, 0, bevel])
                    cylinder(r = bottomDiameter / 2, h = bottomHeight - bevel);

                // Chamfered cap part.
                intersection() {
                    cylinder(r = bottomDiameter / 2, h = bottomHeight);
                    cylinder(r1 = bottomDiameter / 2 - bevel, r2 = bottomDiameter / 2, h = bevel);
                }
            }

    // Cutter to cut the cap buttom, due to the cap being inclined against the floor.
    translate([-bottomDiameter, -bottomDiameter, -bottomDiameter + nothing])
        cube([bottomDiameter * 2, bottomDiameter * 2, bottomDiameter]);
}

function cycle_index(i, max_i) = (
    i < 0     ? cycle_index(max_i + 1 - abs(i), max_i) :
    i > max_i ? cycle_index(i - (max_i + 1), max_i) :
    i
);

assert(cycle_index(-1, 3) == 3);
assert(cycle_index(4, 3) == 0);


function reverse_vector(v) = (
    let(max_i = len(v) - 1)
    [ for (i = [ 0 : max_i]) v[max_i - i] ]
);

assert(reverse_vector([1, 2, 3, 4]) == [4, 3, 2, 1]);


function reverse_deltas(v) = (
    // [ for (delta = reverse_vector(v)) [-1 * delta.x, -1 * delta.y, delta[2]] ]

    let(max_i = len(v) - 1)

    [ 
        for (i = [ 0 : max_i]) 
            [
                -1 * v[max_i - i].x, 
                -1 * v[max_i - i].y, 
                v[cycle_index(max_i - i - 1, max_i)][2]
            ]
    ]
);


function mirror_delta(delta, direction) = (
    direction == "right" || direction == "left" ? [-1 * delta.x,      delta.y, delta[2]] :
    direction == "up"    || direction == "down" ? [     delta.x, -1 * delta.y, delta[2]] :
    undef
);

assert(mirror_delta([-2, 2, 1], "right") == [ 2,  2, 1], "mirror_delta() failed test 1");
assert(mirror_delta([-2, 2, 1], "down")  == [-2, -2, 1], "mirror_delta() failed test 2");


function mirror_deltas(deltas, direction) = (
    [ for (i = [ 0 : len(deltas)-1]) mirror_delta(deltas[i], direction) ]
);

assert(mirror_deltas([[-1, -0.5, 0], [1, -0.5, 0]], "right") == [[1, -0.5, 0], [-1, -0.5, 0]]);


function mirrorextend_deltas(deltas, direction) = (
    let(mirrored_deltas = mirror_deltas(deltas, direction))

    concat(
        deltas, 
        reverse_deltas(
            [ for (i = [ 1 : len(deltas)-1]) mirrored_deltas[i] ]
        )
    )
);


