function nut (e=2,es=10,a=6,b,base=1,h=1,s,center=true,shift=0,grad,z)=
  let(
   
  s=assert(grad!=0)is_undef(s)?is_num(grad)&&is_num(b)?e*(a+b-2*h*tan(90+grad)):
                                       is_undef(es)?assert( is_num(b) && is_num(a),"define a + b")a+b:
                                                    e * es:
                s,
  
  es=is_num(grad)&&is_num(b)?a+b-2*h*tan(90+grad):
                  s/e,

  b=is_undef(grad)?is_undef(b)?es-a:
                               b:
                  2*(h*tan(90+grad))+es-a
  )
 is_num(z)?
   [[s,base,z],[s,0,z],[0,0,z],[0,base,z],
  for(i=[0:e-1])each[
      [b/2+i*es,base,z],    
      [es/2-a/2+shift+i*es,h+base,z],
      [es/2+a/2+shift+i*es,h+base,z],
      [(es-b/2)+i*es,base,z]]
      ]:

   [[s,base],[s,0],[0,0],[0,base],
  for(i=[0:e-1])each[
      [b/2+i*es,base],    
      [es/2-a/2+shift+i*es,h+base],
      [es/2+a/2+shift+i*es,h+base],
      [(es-b/2)+i*es,base]]
      ];
      
      



function involute(r=10,grad=45,fn=fn,rot=0,rev=0,delta=0,z)=
let(
  step=grad/(fn),
  deltaStep=delta/(fn)
)
is_num(z)?
  [for(i=rev?[fn:-1:0] : [0:fn]) [sin(i*step+rot), cos(i*step+rot),0]*r + [sin(i*step-90+rot), cos(i*step-90+rot), 0] * (2*PI*r/360*i*step+i*deltaStep)+[0,0,z]]:
  [for(i=rev?[fn:-1:0] : [0:fn]) [sin(i*step+rot), cos(i*step+rot)]*r + [sin(i*step-90+rot), cos(i*step-90+rot)] * (2*PI*r/360*i*step+i*deltaStep)]
;

function riemen(r1=5,r2=10,tx=20,fn=fn,z,center=false)=
let(a=asin((r2-r1)/tx))
concat(kreis(r=r1,rand=0,grad=180 - 2*a,center=true,fn=fn,z=z,t=[center?-tx/2:0,0]),kreis(r=r2,rand=0,grad=180 + 2*a,t=[center?tx/2:tx,0],rot=180,center=true,fn=fn,z=z));



