Nut_Flanged_Specs = struct_set([], [
    // Metric Flanged Nuts (DIN 6923 / ISO 4162)
    // [S, dc, c, m]
    // M2 is not available in specs
    "M3",   [6,     7.8,    0.8,    3.7],
