    "3/8",  [0.625 * INCH,  0.750 * INCH,  0.04 * INCH,  0.347 * INCH],
    "7/16", [0.688 * INCH,  0.937 * INCH,  0.04 * INCH,  0.395 * INCH],
    "1/2",  [0.750 * INCH,  1.031 * INCH,  0.05 * INCH,  0.458 * INCH],
